import React, { useEffect, useState } from 'react';
import { Page } from '../components/Layout';
import { getAllBookings, updateBookingStatus } from '../services/authService';

export default function AllBookingsAdminPage() {
  const [bookings, setBookings] = useState([]);
  const [error, setError] = useState('');
  const [selected, setSelected] = useState(null);
  const [status, setStatus] = useState('Pending');

  useEffect(() => {
    const load = async () => {
      try {
        const data = await getAllBookings();
        setBookings(data.bookings || []);
      } catch (err) {
        setError('Unable to load booking requests.');
      }
    };

    load();
  }, []);

  const saveStatus = async () => {
    if (!selected) return;

    try {
      const data = await updateBookingStatus(selected.id, status);
      if (data.success) {
        setBookings((current) =>
          current.map((booking) =>
            booking.id === selected.id
              ? {
                  ...booking,
                  status,
                  payment: status === 'Cancelled' ? 'Cancelled' : booking.payment
                }
              : booking
          )
        );
        setSelected(null);
      }
    } catch (err) {
      setError('Unable to update booking.');
    }
  };

  return (
    <Page title="Admin Bookings" subtitle="Review pending requests and approve or cancel them.">
      {error && <div className="alert error">{error}</div>}
      <div className="tableCard">
        <table>
          <thead>
            <tr>
              <th>Car</th>
              <th>Booking ID</th>
              <th>Customer</th>
              <th>From</th>
              <th>To</th>
              <th>Price</th>
              <th>Status</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {bookings.length === 0 && (
              <tr>
                <td colSpan="8">No bookings found.</td>
              </tr>
            )}
            {bookings.map((booking) => (
              <tr key={booking.id}>
                <td>{booking.car}</td>
                <td>{booking.id}</td>
                <td>{booking.customer}</td>
                <td>{booking.from}</td>
                <td>{booking.to}</td>
                <td>₹{Number(booking.price || 0).toLocaleString()}</td>
                <td><span className={`status ${booking.status?.toLowerCase()}`}>{booking.status}</span></td>
                <td>
                  <button
                    className="button small"
                    onClick={() => {
                      setSelected(booking);
                      setStatus(booking.status || 'Pending');
                    }}
                  >
                    View
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {selected && (
        <div className="modalBackdrop">
          <div className="modal card">
            <h3>Booking Decision</h3>
            <p><strong>{selected.car}</strong> for {selected.customer}</p>
            <p>{selected.from} to {selected.to}</p>
            <label>
              Status
              <select value={status} onChange={(e) => setStatus(e.target.value)}>
                <option value="Pending">Pending</option>
                <option value="Approved">Approved</option>
                <option value="Cancelled">Cancelled</option>
              </select>
            </label>
            <div className="cardRow">
              <button className="button muted" onClick={() => setSelected(null)}>Close</button>
              <button className="button" onClick={saveStatus}>Save Decision</button>
            </div>
          </div>
        </div>
      )}
    </Page>
  );
}
